import{_ as s,o as a,c as t,ag as n}from"./chunks/framework.BYehg5q7.js";const y=JSON.parse('{"title":"Cross-Device Sync","description":"","frontmatter":{},"headers":[],"relativePath":"guide/cross-device-sync.md","filePath":"guide/cross-device-sync.md","lastUpdated":1775031224000}'),i={name:"guide/cross-device-sync.md"};function o(r,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="cross-device-sync" tabindex="-1">Cross-Device Sync <a class="header-anchor" href="#cross-device-sync" aria-label="Permalink to &quot;Cross-Device Sync&quot;">​</a></h1><p>getbased can sync your profiles, lab data, and AI settings across multiple devices using end-to-end encrypted CRDT sync. The relay server only sees ciphertext — your data is encrypted before it leaves your browser.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Sync is powered by <a href="https://www.evolu.dev/" target="_blank" rel="noreferrer">Evolu</a>, a local-first CRDT (Conflict-free Replicated Data Type) engine. When you enable sync:</p><ol><li>A <strong>24-word mnemonic</strong> is generated — this is your sync identity and encryption key</li><li>Your data is encrypted with a key derived from this mnemonic and pushed to a relay server</li><li>Other devices using the same mnemonic can pull and decrypt your data</li></ol><p>The relay server stores only encrypted blobs. Without your mnemonic, the data is unreadable.</p><h2 id="setting-up-sync" tabindex="-1">Setting Up Sync <a class="header-anchor" href="#setting-up-sync" aria-label="Permalink to &quot;Setting Up Sync&quot;">​</a></h2><h3 id="first-device-new-setup" tabindex="-1">First Device (New Setup) <a class="header-anchor" href="#first-device-new-setup" aria-label="Permalink to &quot;First Device (New Setup)&quot;">​</a></h3><ol><li>Open <strong>Settings → Data</strong></li><li>Toggle <strong>Cross-device sync</strong> on</li><li>In the setup modal, click <strong>New setup</strong></li><li>Your 24-word mnemonic is displayed in cleartext — <strong>write it down and store it offline</strong></li><li>Check &quot;I have saved my mnemonic somewhere safe&quot;</li><li>Click <strong>Done</strong></li></ol><p>Your data is now syncing to the relay. All profiles are pushed automatically.</p><h3 id="additional-devices-join-existing" tabindex="-1">Additional Devices (Join Existing) <a class="header-anchor" href="#additional-devices-join-existing" aria-label="Permalink to &quot;Additional Devices (Join Existing)&quot;">​</a></h3><ol><li>Open <strong>Settings → Data</strong></li><li>Toggle <strong>Cross-device sync</strong> on</li><li>In the setup modal, click <strong>Join existing</strong></li><li>Paste your 24-word mnemonic from your first device</li><li>Click <strong>Restore</strong></li></ol><p>The page reloads and pulls your data from the relay. All profiles and AI settings sync over.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Anyone with your mnemonic can access your synced data. Treat it like a password — store it offline, never share it.</p></div><h2 id="what-syncs" tabindex="-1">What Syncs <a class="header-anchor" href="#what-syncs" aria-label="Permalink to &quot;What Syncs&quot;">​</a></h2><ul><li><p>All profile data (lab entries, context cards, notes, supplements, cycle data, custom markers, EMF assessments)</p></li><li><p>Profile metadata (name, sex, DOB, location, tags)</p></li><li><p>AI settings (provider, API keys, model selections, Venice E2EE toggle)</p></li><li><p>Chat threads, messages, and custom personalities</p></li><li><p>Display preferences (unit system, range mode, chart overlays)</p></li></ul><p>Settings such as theme are device-specific and do not sync.</p><h2 id="mnemonic-security" tabindex="-1">Mnemonic Security <a class="header-anchor" href="#mnemonic-security" aria-label="Permalink to &quot;Mnemonic Security&quot;">​</a></h2><p>Your mnemonic is your encryption key. getbased takes several precautions:</p><ul><li><strong>Masked by default</strong> — shown as bullet characters in Settings, with a Show/Hide toggle</li><li><strong>Clipboard auto-clear</strong> — when you copy the mnemonic, the clipboard is cleared after 60 seconds</li><li><strong>No server storage</strong> — the mnemonic is generated and stored locally by the Evolu engine, never sent to any server</li></ul><h3 id="regenerating-your-mnemonic" tabindex="-1">Regenerating Your Mnemonic <a class="header-anchor" href="#regenerating-your-mnemonic" aria-label="Permalink to &quot;Regenerating Your Mnemonic&quot;">​</a></h3><p>Disabling sync resets your identity — the page reloads to clean up the sync engine. Re-enabling sync generates a fresh mnemonic. Your other devices will need to join with the new mnemonic.</p><div class="danger custom-block"><p class="custom-block-title">No recovery</p><p>If you lose your mnemonic, there is no way to recover your sync identity. You can still access your local data, but you will need to set up sync again with a new mnemonic on all devices.</p></div><h2 id="sync-status-indicator" tabindex="-1">Sync Status Indicator <a class="header-anchor" href="#sync-status-indicator" aria-label="Permalink to &quot;Sync Status Indicator&quot;">​</a></h2><p>When sync is enabled, a small colored dot appears in the header (next to the settings gear):</p><table tabindex="0"><thead><tr><th>Dot</th><th>Meaning</th></tr></thead><tbody><tr><td>🟢 Green</td><td>Synced — relay connected, data confirmed</td></tr><tr><td>🔵 Blue (pulsing)</td><td>Syncing — push or pull in progress</td></tr><tr><td>🟡 Amber</td><td>Offline — relay unreachable, changes saved locally</td></tr><tr><td>🔴 Red</td><td>Error — sync failed</td></tr></tbody></table><p><strong>Click the dot</strong> to see details: relay connectivity, last push/pull timestamps, and a &quot;Sync now&quot; button for manual retry. The &quot;Settings&quot; link opens the Data tab directly.</p><p>The indicator checks relay connectivity every 60 seconds and monitors Evolu&#39;s error channel for connection drops.</p><h2 id="conflict-resolution" tabindex="-1">Conflict Resolution <a class="header-anchor" href="#conflict-resolution" aria-label="Permalink to &quot;Conflict Resolution&quot;">​</a></h2><p>Sync uses <strong>last-write-wins</strong> at the profile level, based on timestamps. This is designed for single-user, multi-device use — one person using getbased on their phone and laptop. If you edit the same profile on two devices simultaneously before they sync, the most recent push wins.</p><h2 id="relay-server" tabindex="-1">Relay Server <a class="header-anchor" href="#relay-server" aria-label="Permalink to &quot;Relay Server&quot;">​</a></h2><p>The relay is a blind store-and-forward server — it holds encrypted blobs and broadcasts them to your other devices. It never sees your plaintext data.</p><p>By default, sync connects to <code>wss://sync.getbased.health</code>. When accessing the app via <a href="./tor-access.html">Tor</a>, the relay automatically switches to the .onion address (<code>ws://</code>). You can also change the relay in <strong>Settings → Data → Advanced</strong> to point to your own. A status indicator (green/red dot) shows whether the relay is reachable.</p><h3 id="running-your-own-relay" tabindex="-1">Running Your Own Relay <a class="header-anchor" href="#running-your-own-relay" aria-label="Permalink to &quot;Running Your Own Relay&quot;">​</a></h3><p>The relay is open source (<a href="https://github.com/evoluhq/evolu/tree/main/apps/relay" target="_blank" rel="noreferrer">Evolu relay</a>). It runs as a single Docker container with an embedded SQLite database — no external dependencies.</p><p><strong>Requirements:</strong> Any Linux VPS (1 CPU, 1GB RAM, $5/mo), Docker, and a domain with TLS.</p><p><strong>1. Start the relay:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> evolu-relay</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --network</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unless-stopped</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  evoluhq/relay:latest</span></span></code></pre></div><p>This starts the relay on port 4000 (WebSocket only, no HTTP).</p><p><strong>2. Add TLS with Caddy:</strong></p><p>Install <a href="https://caddyserver.com/" target="_blank" rel="noreferrer">Caddy</a> and create <code>/etc/caddy/Caddyfile</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sync.yourdomain.com {</span></span>
<span class="line"><span>    reverse_proxy 127.0.0.1:4000 {</span></span>
<span class="line"><span>        transport http {</span></span>
<span class="line"><span>            versions h1</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>The <code>versions h1</code> directive is required — WebSocket upgrades need HTTP/1.1.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> caddy</span></span></code></pre></div><p>Caddy auto-provisions a TLS certificate via Let&#39;s Encrypt.</p><p><strong>3. Point DNS:</strong> Add an A record for <code>sync.yourdomain.com</code> → your server&#39;s IP.</p><p><strong>4. Use it:</strong> In getbased, go to <strong>Settings → Data → Advanced</strong> and enter <code>wss://sync.yourdomain.com</code>. The status dot turns green when connected.</p><div class="tip custom-block"><p class="custom-block-title">Security hardening</p><p>For a production relay, disable SSH password auth, enable UFW firewall (allow only 22, 80, 443), and enable unattended-upgrades for automatic security patches.</p></div><h2 id="relationship-to-encryption" tabindex="-1">Relationship to Encryption <a class="header-anchor" href="#relationship-to-encryption" aria-label="Permalink to &quot;Relationship to Encryption&quot;">​</a></h2><p>Cross-device sync and <a href="./encryption.html">local encryption</a> are independent systems:</p><ul><li><strong>Local encryption</strong> (passphrase → AES-256-GCM) protects your localStorage data at rest on each device</li><li><strong>Sync encryption</strong> (mnemonic → Evolu&#39;s key derivation → XChaCha20-Poly1305) protects data in transit and on the relay</li></ul><p>You can use either, both, or neither. Enabling local encryption does not affect sync, and vice versa.</p>`,52)])])}const u=s(i,[["render",o]]);export{y as __pageData,u as default};
